python3 << 'EOF'
import json
import glob

# Collect all unique fingerprints from patterns files
all_fingerprints = {}
all_iterators = {}

patterns_files = glob.glob('/local/nick/ai_iree/dataset*/patterns.json')[:10]

for pf in patterns_files:
    try:
        with open(pf) as f:
            data = json.load(f)

        # Named ops
        if 'named_ops' in data:
            for op_name, op_info in data['named_ops'].items():
                key = f"NAMED: {op_name}"
                if 'iterator_types' in op_info:
                    dims = len(op_info['iterator_types'])
                    if key not in all_iterators:
                        all_iterators[key] = {
                            'dims': dims,
                            'types': op_info['iterator_types'],
                            'count': 0
                        }
                    all_iterators[key]['count'] += op_info.get('total_count', 0)

        # Fused ops
        if 'fused_ops' in data:
            for op_id, op_info in data['fused_ops'].items():
                fp = op_info.get('fingerprint', 'UNKNOWN')
                if fp not in all_fingerprints:
                    all_fingerprints[fp] = {
                        'primary_op': op_info.get('primary_op'),
                        'iterator_types': op_info.get('iterator_types'),
                        'num_patterns': 0,
                        'total_count': 0
                    }
                all_fingerprints[fp]['num_patterns'] += len(op_info.get('shape_patterns', []))
                all_fingerprints[fp]['total_count'] += op_info.get('total_count', 0)
    except:
        pass

print("NAMED OPERATIONS (from patterns.json):")
print(f"{'Operation':<40} {'Dims':<6} {'Iterator Types':<50} {'Count'}")
print("-" * 120)
for key in sorted(all_iterators.keys()):
    info = all_iterators[key]
    iter_str = ', '.join(info['types'])
    op_name = key.replace('NAMED: ', '')
    print(f"{op_name:<40} {info['dims']:<6} {iter_str:<50} {info['count']}")

print(f"\n\nFUSED OPERATION PATTERNS SUMMARY ({len(all_fingerprints)} unique):")
print(f"Primary patterns by iteration space:")

# Group by dims
by_dims = {}
for fp, info in all_fingerprints.items():
    dims = len(info['iterator_types']) if info['iterator_types'] else 0
    if dims not in by_dims:
        by_dims[dims] = []
    by_dims[dims].append((fp, info))

for dims in sorted(by_dims.keys()):
    patterns = by_dims[dims]
    print(f"\n{dims}D iteration space:")
    iter_types = patterns[0][1]['iterator_types'] if patterns else []
    print(f"  Iterator types: {iter_types}")
    print(f"  Number of unique generic patterns: {len(patterns)}")
    print(f"  Sample fingerprints:")
    for fp, info in patterns[:3]:
        print(f"    - {fp[:60]}...")
